    protected function extractPreview(string $html, string $url): array
    {
        $title = null;
        $description = null;
        $image = null;

        libxml_use_internal_errors(true);
        $dom = new \DOMDocument();

        $loaded = @$dom->loadHTML($html);
        if ($loaded) {
            $xpath = new \DOMXPath($dom);

            $titleNode = $xpath->query('//meta[@property="og:title"]/@content')->item(0)
                ?? $xpath->query('//title')->item(0);

            if ($titleNode) {
                $title = trim($titleNode->nodeValue);
            }

            $descriptionNode = $xpath->query('//meta[@property="og:description"]/@content')->item(0)
                ?? $xpath->query('//meta[@name="description"]/@content')->item(0);

            if ($descriptionNode) {
                $description = trim($descriptionNode->nodeValue);
            }

            $imageNode = $xpath->query('//meta[@property="og:image"]/@content')->item(0);

            if ($imageNode) {
                $image = trim($imageNode->nodeValue);
            }
        }

        libxml_clear_errors();

        return [
            'title' => $title,
            'description' => $description,
            'image' => $image ? $this->resolveUrl($image, $url) : null,
        ];
