    protected function parseHeaders(string $rawHeaders): array
    {
        $lines = preg_split("/\r\n|\n|\r/", trim($rawHeaders));
        $parsed = [];

        foreach ($lines as $line) {
            if (str_contains($line, ':')) {
                [$key, $value] = explode(':', $line, 2);
                $parsed[trim($key)] = trim($value);
            }
        }

        return $parsed;
    }

    protected function resolveUrl(string $resource, string $base): string
    {
        if (filter_var($resource, FILTER_VALIDATE_URL)) {
            return $resource;
        }

        $baseParts = parse_url($base);
        $scheme = $baseParts['scheme'] ?? 'https';
        $host = $baseParts['host'] ?? '';
        $port = isset($baseParts['port']) ? ':' . $baseParts['port'] : '';

        if (str_starts_with($resource, '//')) {
            return $scheme . ':' . $resource;
        }

        if (str_starts_with($resource, '/')) {
            return $scheme . '://' . $host . $port . $resource;
        }

        $path = $baseParts['path'] ?? '/';
        $dir = rtrim(str_replace('\\', '/', dirname($path)), '/');
        $dir = $dir === '' ? '' : $dir;

        return $scheme . '://' . $host . $port . $dir . '/' . ltrim($resource, '/');
    }

    protected function isSafeHost(string $host): bool
    {
        if (filter_var($host, FILTER_VALIDATE_IP)) {
            return $this->isPublicIp($host);
        }

        $records = @dns_get_record($host, DNS_A + DNS_AAAA);
        if ($records === false || $records === []) {
            return false;
        }

        foreach ($records as $record) {
            $ip = $record['ip'] ?? $record['ipv6'] ?? null;
            if (!$ip || !$this->isPublicIp($ip)) {
                return false;
            }
        }

        return true;
    }

    protected function isPublicIp(string $ip): bool
    {
        return filter_var(
            $ip,
            FILTER_VALIDATE_IP,
            FILTER_FLAG_NO_PRIV_RANGE | FILTER_FLAG_NO_RES_RANGE
        ) !== false;
    }
